// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper: Get priority badge variant and color
function getPriorityVariant(priority?: string): 'default' | 'success' | 'warning' | 'error' {
  switch (priority) {
    case 'high': return 'error';
    case 'medium': return 'warning';
    case 'low': return 'success';
    default: return 'default';
  }
}

// Helper: Format due date to readable string
function formatDueDate(dueDate?: string): string {
  if (!dueDate) return '';
  try {
    const date = new Date(dueDate);
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  } catch {
    return dueDate;
  }
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state for task management
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTaskInColumn, setAddingTaskInColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  // Sync with props
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Handle incoming task updates from stream
  useEffect(() => {
    if (taskChanged.latest) {
      const { action: changeAction, task: changedTask } = taskChanged.latest;
      if (!changedTask?.id) return;

      setTasks((prevTasks) => {
        if (changeAction === 'delete') {
          return prevTasks.filter((t) => t.id !== changedTask.id);
        } else if (changeAction === 'create') {
          return [...prevTasks, changedTask];
        } else {
          // move, edit, or unknown action
          return prevTasks.map((t) => (t.id === changedTask.id ? { ...t, ...changedTask } : t));
        }
      });
    }
  }, [taskChanged.latest]);

  // Compute tasks by column
  const tasksByColumn = useMemo(() => {
    const map: Record<string, typeof tasks> = {};
    (props.columns || []).forEach((col) => {
      map[col.id || ''] = [];
    });
    tasks.forEach((task) => {
      const colId = task.column || 'todo';
      if (!map[colId]) map[colId] = [];
      map[colId].push(task);
    });
    return map;
  }, [tasks, props.columns]);

  // Summary stats
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  // Add new task
  const handleAddTask = useCallback(() => {
    if (!newTaskTitle.trim() || !addingTaskInColumn) return;
    const taskId = `task-${Date.now()}`;
    const newTask = {
      id: taskId,
      title: newTaskTitle,
      priority: newTaskPriority,
      column: addingTaskInColumn,
    };
    setTasks((prev) => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId, data: { column: addingTaskInColumn } });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingTaskInColumn(null);
  }, [newTaskTitle, newTaskPriority, addingTaskInColumn, taskUpdate]);

  // Move task to another column
  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t))
    );
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [taskUpdate]);

  // Edit task title
  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
    );
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo' } });
    setEditingTaskId(null);
    setEditingTitle('');
  }, [tasks, taskUpdate]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Card shadow="md" padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Heading level={3} color="var(--ggui-color-primary-900)">Task Board</Heading>
              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" />
              <Text variant="body" color="var(--ggui-color-primary-700)">
                <strong>{completedTasks}</strong> of <strong>{totalTasks}</strong> completed
              </Text>
            </Stack>
            <Progress
              value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0}
              max={100}
              variant="success"
              size="md"
              showLabel={false}
            />
          </Stack>
        </Card>

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap={true}>
          {(props.columns || []).map((column) => {
            const columnTasks = tasksByColumn[column.id || ''] || [];
            const isAddingInThisColumn = addingTaskInColumn === column.id;

            return (
              <Box
                key={column.id}
                padding="var(--ggui-spacing-4)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-lg)"
                style={{ minWidth: '300px', flex: '0 1 auto' }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Column Header */}
                  <Stack direction="horizontal" justify="between" align="center">
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                      <Heading level={4} color="var(--ggui-color-onSurface)">{column.name}</Heading>
                      <Badge variant="secondary" size="sm">{columnTasks.length}</Badge>
                    </Stack>
                  </Stack>

                  <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

                  {/* Task Cards */}
                  <Stack gap="var(--ggui-spacing-2)" style={{ minHeight: '200px' }}>
                    {columnTasks.map((task) => {
                      const isEditing = editingTaskId === task.id;
                      const priorityVariant = getPriorityVariant(task.priority);
                      const dueStr = formatDueDate(task.dueDate);

                      return (
                        <Card
                          key={task.id}
                          shadow="sm"
                          padding="var(--ggui-spacing-3)"
                          border={true}
                          radius="md"
                          background="var(--ggui-color-surface)"
                        >
                          <Stack gap="var(--ggui-spacing-2)">
                            {/* Task Title (Editable) */}
                            {isEditing ? (
                              <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
                                <Input
                                  label="Edit task title"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  placeholder="Task title"
                                  size="sm"
                                  style={{ flex: 1 }}
                                />
                                <Button
                                  variant="primary"
                                  size="sm"
                                  onClick={() => handleEditTask(task.id || '', editingTitle)}
                                >
                                  Save
                                </Button>
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => setEditingTaskId(null)}
                                >
                                  Cancel
                                </Button>
                              </Stack>
                            ) : (
                              <Box as={Clickable} onClick={() => {
                                setEditingTaskId(task.id || null);
                                setEditingTitle(task.title || '');
                              }}>
                                <Text
                                  variant="body"
                                  color="var(--ggui-color-onSurface)"
                                  style={{ fontWeight: 500 }}
                                >
                                  {task.title || 'Untitled Task'}
                                </Text>
                              </Box>
                            )}

                            {/* Priority Badge */}
                            {task.priority && (
                              <Badge variant={priorityVariant} size="sm" pill={true}>
                                {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                              </Badge>
                            )}

                            {/* Assignee & Due Date */}
                            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                              {task.assignee && (
                                <Avatar name={task.assignee} size="sm" />
                              )}
                              {dueStr && (
                                <Row gap="var(--ggui-spacing-1)" align="center">
                                  <Icon name="calendar" size={14} color="var(--ggui-color-onSurfaceVariant)" />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{dueStr}</Text>
                                </Row>
                              )}
                            </Stack>
                            {/* Move to Column Dropdown */}
                            <Dropdown
                              trigger={<Button variant="outline" size="sm" fullWidth={true}>Move to...</Button>}
                              options={(props.columns || []).map((col) => ({
                                value: col.id || '',
                                label: col.name || 'Unknown',
                                disabled: col.id === column.id,
                              }))}
                              value={column.id || ''}
                              onChange={(newCol) => handleMoveTask(task.id || '', newCol)}
                              placement="bottom-start"
                            />
                           </Stack>
                         </Card>
                       );
                     })}
                   </Stack>

                   {/* Add Task Form */}
                   {isAddingInThisColumn ? (
                     <Card shadow="sm" padding="var(--ggui-spacing-3)" border={true} radius="md" background="var(--ggui-color-primary-50)">
                       <Stack gap="var(--ggui-spacing-2)">
                         <Input
                           label="Task title"
                           value={newTaskTitle}
                           onChange={setNewTaskTitle}
                           placeholder="Enter task title"
                           size="sm"
                         />
                         <Select
                           label="Priority"
                           value={newTaskPriority}
                           onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                           options={[
                             { value: 'low', label: 'Low' },
                             { value: 'medium', label: 'Medium' },
                             { value: 'high', label: 'High' },
                           ]}
                           size="sm"
                         />
                         <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
                           <Button
                             variant="primary"
                             size="sm"
                             fullWidth={true}
                             onClick={handleAddTask}
                           >
                             Add Task
                           </Button>
                           <Button
                             variant="ghost"
                             size="sm"
                             fullWidth={true}
                             onClick={() => {
                               setAddingTaskInColumn(null);
                               setNewTaskTitle('');
                               setNewTaskPriority('medium');
                             }}
                           >
                             Cancel
                           </Button>
                         </Stack>
                       </Stack>
                     </Card>
                   ) : (
                     <Button
                       variant="secondary"
                       size="sm"
                       fullWidth={true}
                       onClick={() => setAddingTaskInColumn(column.id || '')}
                     >
                       + Add Task
                     </Button>
                   )}
                 </Stack>
               </Box>
             );
           })}
         </Row>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}
